// Nxgn.Actions.Api/Features/Admin/Workflows/Save/SaveWorkflowValidator.cs

public class SaveWorkflowValidator : Validator<SaveWorkflowRequest>
{
    public SaveWorkflowValidator()
    {
        RuleFor(x => x.Code)
            .NotEmpty()
            .MaximumLength(100)
            .Matches("^[a-z0-9-]+$");
    }
}

// Nxgn.Actions.Api/Features/Admin/EscalationRules/Save/SaveEscalationRuleValidator.cs

public class SaveEscalationRuleValidator : Validator<SaveEscalationRuleRequest>
{
    public SaveEscalationRuleValidator()
    {
        RuleFor(x => x.Name)
            .NotEmpty()
            .MaximumLength(200);

        RuleFor(x => x.Severity)
            .NotNull();

        RuleFor(x => x.Severity.Id)
            .GreaterThanOrEqualTo(0)
            .When(x => x.Severity is not null);
    }
}

